// Build a structured failure notification payload.
const error = $input.first().json;

const workflowName = error.workflow?.name || 'Unknown workflow';
const executionId  = error.execution?.id  || 'unknown';
const errorMessage = error.execution?.error?.message || 'Unknown error';
const errorNode    = error.execution?.error?.node?.name || 'Unknown node';
const timestamp    = new Date().toISOString();

const text = [
  `🚨 <b>Workflow Failure</b>`,
  ``,
  `<b>Workflow:</b> ${workflowName}`,
  `<b>Node:</b> ${errorNode}`,
  `<b>Error:</b> ${errorMessage}`,
  `<b>Execution ID:</b> ${executionId}`,
  `<b>Time:</b> ${timestamp}`
].join('\n');

return [{ json: { text, workflowName, executionId, errorMessage, errorNode, timestamp } }];
